### iOS Document Scanner with VisionKit

Source: https://context7.com/dariyd/react-native-document-scanner/llms.txt

Implements document scanning on iOS using VNDocumentCameraViewController. Supports both old and new React Native architectures. Handles image capture, format conversion (PNG/JPEG) based on quality, and temporary file storage.

```objective-c
// DocumentScanner.mm - Core iOS implementation
#import "DocumentScanner.h"
#import <VisionKit/VisionKit.h>

// New Architecture: TurboModule protocol implementation
#ifdef RCT_NEW_ARCH_ENABLED
- (void)launchScanner:(JS::NativeDocumentScanner::Options &)options
             callback:(RCTResponseSenderBlock)callback
{
    // Convert C++ struct to NSDictionary
    NSMutableDictionary *opts = [NSMutableDictionary new];
    if (options.quality().has_value()) {
        opts[@"quality"] = @(options.quality().value());
    }

    dispatch_async(dispatch_get_main_queue(), ^{
        VNDocumentCameraViewController *scanner = [[VNDocumentCameraViewController alloc] init];
        scanner.delegate = self;
        [RCTPresentedViewController() presentViewController:scanner animated:YES completion:nil];
    });
}
#endif

// Delegate method: Handle successful scan
- (void)documentCameraViewController:(VNDocumentCameraViewController *)controller
                    didFinishWithScan:(VNDocumentCameraScan *)scan
{
    NSMutableArray *scannedImages = [NSMutableArray array];
    for (int i = 0; i < [scan pageCount]; i++) {
        UIImage *image = [scan imageOfPageAtIndex:i];

        // Quality determines format: PNG (1.0) or JPEG (<1.0)
        NSData *data = quality < 1.0
            ? UIImageJPEGRepresentation(image, quality)
            : UIImagePNGRepresentation(image);

        NSString *fileName = [[NSUUID UUID] UUIDString];
        NSString *path = [NSTemporaryDirectory() stringByAppendingPathComponent:fileName];
        [data writeToFile:path atomically:YES];

        [scannedImages addObject:@{
            @"uri": [[NSURL fileURLWithPath:path] absoluteString],
            @"fileName": fileName,
            @"width": @(image.size.width),
            @"height": @(image.size.height),
            @"fileSize": @(data.length),
            @"type": quality < 1.0 ? @"image/jpeg" : @"image/png"
        }];
    }

    [controller dismissViewControllerAnimated:YES completion:^{
        callback(@[@{ @"images": scannedImages }]);
    }];
}

```

